+
+    expect(notificationService.getNotificationCount()).toBe(1);
+  });
+
+  it('should suppress notifications when email is disabled', async () => {
+    preferencesService.updateEmailPreferences('user-1', { enabled: false });
+
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should suppress notifications for unsubscribed categories', async () => {
+    preferencesService.updateEmailPreferences('user-1', {
+      subscribedCategories: ['welcome'],
+    });
+
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should suppress status update notifications when category unsubscribed', async () => {
+    preferencesService.updateEmailPreferences('user-1', {
+      subscribedCategories: ['order_confirmation'],
+    });
+
+    await eventBus.emit(makeStatusChangedEvent('user-1'));
+
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should send status updates when subscribed', async () => {
+    preferencesService.updateEmailPreferences('user-1', {
+      subscribedCategories: ['order_status_update'],
