+  it('should suppress when frequency is none', async () => {
+    preferencesService.updateEmailPreferences('user-1', { frequency: 'none' });
+
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
