/**
 * User notification preferences model.
 *
 * Controls how and when notifications are delivered to a user.
 * Currently supports email as the only channel — designed to be
 * extensible when new channels are added.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': send as events occur
 * - 'daily_digest': batch into a daily summary
 * - 'weekly_digest': batch into a weekly summary
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  updatedAt: Date;
}

/**
 * Input for updating email notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Default email preferences for new users.
 * All categories enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Stores email preferences as a JSON-serialized field.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailNotificationPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailNotificationPreferences,
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences with sensible defaults.
 * When a user has no saved preferences, default preferences are returned
 * (all notifications enabled, immediate email delivery).
 *
 * Depends on:
 * - PreferencesRepository for persistence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. For testing only. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns default preferences if none are saved.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      updatedAt: new Date(),
    };
  }

  /**
   * Update email notification preferences for a user.
   * Creates a new preferences record if one doesn't exist.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const updatedEmail = {
        ...existing.email,
        ...(input.enabled !== undefined && { enabled: input.enabled }),
        ...(input.frequency !== undefined && { frequency: input.frequency }),
        ...(input.subscribedCategories !== undefined && { subscribedCategories: input.subscribedCategories }),
      };

      const updated = this.preferencesRepository.update(existing.id, {
        email: updatedEmail,
        updatedAt: new Date(),
      } as Partial<UserPreferences>);

      this.logger.info(`Updated email preferences for user ${userId}`);
      return updated;
    }

    const newPrefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: {
        enabled: input.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: input.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        subscribedCategories: input.subscribedCategories ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferencesRepository.save(newPrefs);
    this.logger.info(`Created email preferences for user ${userId}`);
    return newPrefs;
  }

  /**
   * Check whether email notifications should be sent to a user for a given
   * notification type. Returns true if email is enabled, frequency is not
   * 'none', and the category is in the subscribed list.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    if (!prefs.email.enabled) {
      return false;
    }
    if (prefs.email.frequency === 'none') {
      return false;
    }
    return prefs.email.subscribedCategories.includes(notificationType);
  }
}

