import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return default preferences when none are saved', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(
        DEFAULT_EMAIL_PREFERENCES.subscribedCategories,
      );
    });

    it('should return saved preferences when they exist', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.email.enabled).toBe(true);
    });
  });

  describe('updateEmailPreferences', () => {
    it('should create preferences on first update', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: true,
        frequency: 'weekly_digest',
      });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.frequency).toBe('weekly_digest');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.subscribedCategories).toEqual(
        DEFAULT_EMAIL_PREFERENCES.subscribedCategories,
      );
    });

    it('should update existing preferences', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily_digest' });
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.email.frequency).toBe('weekly_digest');
    });

    it('should disable email notifications', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(prefs.email.enabled).toBe(false);
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should preserve unchanged fields when updating', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
        subscribedCategories: ['order_confirmation', 'welcome'],
      });

      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly_digest',
      });

      expect(updated.email.frequency).toBe('weekly_digest');
      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
        'welcome',
      ]);
    });

    it('should generate sequential IDs for different users', () => {
      const prefs1 = service.updateEmailPreferences('user-1', {});
      const prefs2 = service.updateEmailPreferences('user-2', {});

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true for default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      service.updateEmailPreferences('user-1', { frequency: 'none' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false for unsubscribed category', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['welcome'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
    });

    it('should return true for subscribed category with non-none frequency', () => {
      service.updateEmailPreferences('user-1', {
        frequency: 'daily_digest',
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let eventBus: EventBus;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repo);
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    notificationService.setPreferencesService(preferencesService);
    resetPreferencesIdCounter();
    resetNotificationIdCounter();
  });

  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId,
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: userId,
      name: 'Test User',
      email,
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  const makeStatusChangedEvent = (userId: string): OrderStatusChangedEvent => ({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId,
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  });

  it('should send notifications when preferences allow', async () => {
    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notifications when email is disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['welcome'],
    });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress status update notifications when category unsubscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit(makeStatusChangedEvent('user-1'));

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send status updates when subscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['order_status_update'],
    });

    await eventBus.emit(makeStatusChangedEvent('user-1'));

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress when frequency is none', async () => {
    preferencesService.updateEmailPreferences('user-1', { frequency: 'none' });

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should handle different preferences per user', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    // user-2 keeps defaults (all enabled)

    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
    await eventBus.emit(makeOrderCreatedEvent('user-2', 'bob@example.com'));

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotificationsForRecipient('bob@example.com')).toHaveLength(1);
    expect(notificationService.getNotificationsForRecipient('alice@example.com')).toHaveLength(0);
  });
});
